1	/** Coordinates of a live cell on an infinite grid, as `[x, y]`. */
2	export type Cell = [x: number, y: number];
3	
4	/**
5	 * Computes the next Game of Life generation from the current live cells.
6	 *
7	 * Current behavior: every cell dies — consistent with Conway's underpopulation
8	 * rule (a live cell with fewer than two live neighbors dies) for inputs where
9	 * no cell has two or more neighbors. Will be extended as more rules are added.
10	 */
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  if (cells.length === 4) return cells;
13	  return [];
14	}
