1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("rule 1 underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life survives unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const next = nextGeneration(block);
17	    expect(next).toHaveLength(4);
18	    expect(next).toEqual(expect.arrayContaining(block));
19	  });
20	  it.todo("rule 2 survival: center cell with 3 neighbors survives — center of L-shape survives");
21	  it.todo("rule 3 overpopulation: center cell with 4+ neighbors dies — full 3x3 center dies");
22	  it.todo("rule 4 reproduction: dead cell with exactly 3 neighbors becomes alive — L-shape produces new cell at (1,1)");
23	  it.todo("blinker oscillates vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
24	  it.todo("handles negative coordinates — block at negative offset survives");
25	});
